export const Customizer: React.FC<{ product: Product, onBack: () => void }> = ({ product, onBack }) => {
  const [selectedMaterial, setSelectedMaterial] = useState(product.materials[0]);
  const [selectedFinish, setSelectedFinish] = useState(product.finishes[0]);
  const [quantity, setQuantity] = useState(product.pricingTiers[0].minQuantity);
  const [logo, setLogo] = useState<string | null>(null);
  const [isSubscription, setIsSubscription] = useState(false);

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => setLogo(event.target?.result as string);
      reader.readAsDataURL(file);
    }
  };

  const pricing = useMemo(() => {
    const sortedTiers = [...product.pricingTiers].sort((a, b) => b.minQuantity - a.minQuantity);
    const tier = sortedTiers.find(t => quantity >= t.minQuantity) || product.pricingTiers[0];
    let unitPrice = tier.pricePerUnit;
    if (isSubscription) unitPrice *= 0.9; // 10% subscription discount
    return {
      unitPrice,
      total: unitPrice * quantity,
      tierName: tier.label
    };
  }, [quantity, product.pricingTiers, isSubscription]);

  const handleQuantityChange = (val: string) => {
    const num = parseInt(val);
    if (isNaN(num)) {
      setQuantity(0);
    } else {
      setQuantity(Math.max(0, num));
    }
  };

  return (
    <div className="min-h-screen bg-white pt-24 pb-20 px-4 md:px-8">
      <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-16">
        {/* Left: Immersive Preview */}
        <div className="space-y-12 animate-in fade-in duration-1000">
          <button onClick={onBack} className="text-[10px] uppercase tracking-[0.4em] text-gray-400 hover:text-black transition-all flex items-center gap-2">
