export const Customizer: React.FC<{ product: Product, onBack: () => void }> = ({ product, onBack }) => {
  const [selectedTexture, setSelectedTexture] = useState(product.textures?.[0] || '');
  const [selectedEmbossing, setSelectedEmbossing] = useState(product.embossing?.[0] || '');
  const [quantity, setQuantity] = useState(product.pricingTiers[0].minQuantity);
  const [logo, setLogo] = useState<string | null>(null);
  const [isSubscription, setIsSubscription] = useState(false);

  const handleLogoUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (event) => setLogo(event.target?.result as string);
      reader.readAsDataURL(file);
    }
  };

  const pricing = useMemo(() => {
    const sortedTiers = [...product.pricingTiers].sort((a, b) => b.minQuantity - a.minQuantity);
    const tier = sortedTiers.find(t => quantity >= t.minQuantity) || product.pricingTiers[0];
    let unitPrice = tier.pricePerUnit;
    if (isSubscription) unitPrice *= 0.9;
    if (selectedTexture) unitPrice += 3.0;
    if (selectedEmbossing) unitPrice += 5.0;

    return {
      unitPrice,
      total: unitPrice * quantity,
      tierName: tier.label
    };
  }, [quantity, product.pricingTiers, isSubscription, selectedTexture, selectedEmbossing]);

  return (
    <div className="min-h-screen bg-white pt-24 pb-20 px-4 md:px-8 animate-in fade-in transform-gpu">
      <div className="max-w-7xl mx-auto grid grid-cols-1 lg:grid-cols-2 gap-16">
        {/* Left: Preview */}
        <div className="space-y-10">
          <button onClick={onBack} className="text-[10px] uppercase tracking-widest text-gray-400 hover:text-black flex items-center gap-2">
            ← Showroom Archive
          </button>

          <div className="relative aspect-square rounded-[2.5rem] bg-[#f9f9f9] overflow-hidden group shadow-inner border border-gray-50 flex items-center justify-center p-12 transform-gpu">
