            />

            {logo && (
              <div className="absolute inset-0 flex items-center justify-center pointer-events-none transform-gpu animate-in zoom-in">
                <img src={logo} className="w-40 h-40 object-contain opacity-50 grayscale mix-blend-darken rotate-[-2deg]" alt="Logo overlay" />
              </div>
            )}
          </div>

          <div className="grid grid-cols-3 gap-4">
            {Object.entries(product.impactMetrics).map(([key, value]) => (
              <div key={key} className="bg-gray-50 p-6 rounded-2xl text-center border border-gray-100 hover:bg-white transition-all transform-gpu">
                <p className="text-[7px] uppercase tracking-widest text-gray-400 mb-2">{key}</p>
                <p className="font-serif text-lg">{value}</p>
              </div>
            ))}
          </div>
        </div>

        {/* Right: Controls */}
        <div className="space-y-10">
          <div>
            <h1 className="text-4xl md:text-6xl font-serif mb-4">{product.name}</h1>
            <p className="text-gray-400 text-base max-w-lg leading-relaxed">{product.description}</p>
          </div>

          <div className="space-y-8">
            {/* Industry Specific selectors */}
            {product.tier === 'Signature' && (
              <div className="space-y-6">
                <h4 className="text-[9px] uppercase tracking-widest font-bold opacity-30">Artisan Config</h4>
                <div className="flex gap-2 flex-wrap">
                  {product.textures?.map(texture => (
                    <button key={texture} onClick={() => setSelectedTexture(texture)} className={`px-4 py-2 rounded-full text-[8px] uppercase tracking-widest font-bold border transition-all transform-gpu ${selectedTexture === texture ? 'bg-black text-white' : 'bg-gray-50 hover:border-black'}`}>{texture}</button>
                  ))}
                </div>
              </div>
            )}

            <section className="bg-black text-white p-10 rounded-[2.5rem] shadow-xl relative overflow-hidden transform-gpu">
               <div className="relative z-10 space-y-8">
                  <div className="flex justify-between items-end">
                    <div>
                      <h4 className="text-[8px] uppercase tracking-widest text-white/30 mb-2">Per Unit Quote</h4>
                      <p className="text-4xl font-serif">₹{pricing.unitPrice.toFixed(2)}</p>
                    </div>
                    <span className="bg-white/10 px-4 py-1.5 rounded-full text-[8px] uppercase tracking-widest font-bold border border-white/10">{pricing.tierName}</span>
                  </div>

                  <div className="space-y-3">
                    <p className="text-[8px] uppercase tracking-widest font-bold opacity-40">Batch Quantity</p>
                    <input type="number" value={quantity} onChange={(e) => setQuantity(Number(e.target.value))} className="w-full bg-white/10 border border-white/20 rounded-xl py-5 px-8 text-2xl font-serif text-white focus:outline-none focus:ring-1 focus:ring-white/40 transition-all" />
                  </div>

                  <div className="flex items-center justify-between pt-6 border-t border-white/10">
                    <p className="text-[8px] uppercase tracking-widest opacity-40">Total Project Est.</p>
                    <p className="text-2xl font-serif">₹{pricing.total.toLocaleString('en-IN')}</p>
                  </div>
               </div>
            </section>

            <Button size="lg" fullWidth className="h-16 rounded-full shadow-lg">Begin Batch Fabrication</Button>
          </div>
        </div>
      </div>
    </div>
  );
};

