import React, { useState, useEffect, useMemo } from 'react';
import { Industry, Product, IndustryTheme } from './types';
import { PRODUCTS, INDUSTRIES, INDUSTRY_THEMES } from './constants';
import { Button } from './components/Button';
import { Concierge } from './components/Concierge';
import { Customizer } from './components/Customizer';
import { 
  ShoppingBag, 
  Leaf, 
  Menu, 
  Search, 
  ChevronRight, 
  Sparkles, 
  Zap, 
  Globe,
  ArrowRight,
  Maximize2,
  PieChart,
  ShieldCheck,
  PackageCheck,
  Truck,
  Award,
  Clock
} from 'lucide-react';

const App: React.FC = () => {
  const [view, setView] = useState<'onboarding' | 'showroom' | 'customizer'>('onboarding');
  const [selectedIndustry, setSelectedIndustry] = useState<Industry | null>(null);
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);
  const [showConcierge, setShowConcierge] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);

  useEffect(() => {
    let ticking = false;
    const handleScroll = () => {
      if (!ticking) {
        window.requestAnimationFrame(() => {
          setIsScrolled(window.scrollY > 30);
          ticking = false;
        });
        ticking = true;
      }
    };
    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const theme = useMemo((): IndustryTheme => {
    if (!selectedIndustry) return INDUSTRY_THEMES['Fashion'];
    return INDUSTRY_THEMES[selectedIndustry];
  }, [selectedIndustry]);

  const industryProducts = useMemo(() => {
    const prods = !selectedIndustry ? PRODUCTS : PRODUCTS.filter(p => p.industries.includes(selectedIndustry));
    return prods.filter(p => !p.isComingSoon);
  }, [selectedIndustry]);

  const comingSoonProducts = useMemo(() => PRODUCTS.filter(p => p.isComingSoon), []);

  const handleStartDesign = (industry: Industry) => {
    setSelectedIndustry(industry);
    setView('showroom');
    window.scrollTo(0, 0);
  };

  const openCustomizer = (product: Product) => {
    if (product.isComingSoon) return;
    setSelectedProduct(product);
    setView('customizer');
    window.scrollTo(0, 0);
  };

