import React, { useState, useEffect } from 'react';
import { Button } from './Button';
import { CartItem } from '../App';
import { Loader2, Check, FileText, ClipboardCheck, Box, Zap, Calendar, ArrowLeft } from 'lucide-react';

interface CheckoutProps {
  cart: CartItem[];
  total: number;
  onBack: () => void;
  onComplete: () => void;
}

type CheckoutStep = 'summary' | 'processing' | 'confirmed';

export const Checkout: React.FC<CheckoutProps> = ({ cart, total, onBack, onComplete }) => {
  const [step, setStep] = useState<CheckoutStep>('summary');
  const [loadingStep, setLoadingStep] = useState(0);

  const loadingSteps = [
    "Authorizing Transaction...",
    "Securing Factory Slots...",
    "Allocating Logistics Partners...",
    "Generating Production Briefs..."
  ];

  useEffect(() => {
    if (step === 'processing') {
      const interval = setInterval(() => {
        setLoadingStep(s => {
          if (s >= loadingSteps.length - 1) {
            clearInterval(interval);
            setTimeout(() => setStep('confirmed'), 1000);
            return s;
          }
          return s + 1;
        });
      }, 1500);
      return () => clearInterval(interval);
    }
  }, [step]);

  if (step === 'processing') {
    return (
      <div className="fixed inset-0 z-[100] bg-luxury-black flex flex-col items-center justify-center text-soft-white px-8 text-center animate-in fade-in duration-700">
        <div className="relative mb-12">
          <Loader2 className="w-20 h-20 text-champagne-gold animate-spin stroke-[1px]" />
          <div className="absolute inset-0 bg-champagne-gold blur-3xl opacity-20 animate-pulse" />
        </div>
        <h2 className="text-4xl font-serif mb-4 tracking-tight italic">Processing Project Protocol</h2>
        <p className="text-champagne-gold text-[10px] uppercase tracking-[0.6em] font-bold animate-pulse">
          {loadingSteps[loadingStep]}
        </p>
      </div>
    );
  }

  if (step === 'confirmed') {
    return (
      <div className="min-h-screen bg-soft-white pt-40 px-8 flex flex-col items-center">
        <div className="max-w-3xl w-full animate-in slide-in-from-bottom duration-1000">
          <div className="w-20 h-20 bg-champagne-gold rounded-full flex items-center justify-center shadow-xl mb-12">
            <Check className="text-luxury-black w-10 h-10 stroke-[3px]" />
          </div>
          <h1 className="text-6xl md:text-8xl font-serif leading-none tracking-tighter mb-8">Projects <br /><span className="italic text-champagne-gold font-light">Authenticated.</span></h1>
          <p className="text-gray-500 text-xl font-light leading-relaxed mb-16">
            Your production sequence is now active. Projects <span className="text-luxury-black font-bold">#{Math.floor(Math.random() * 900000 + 100000)}</span> have been registered.
          </p>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-16">
            <div className="p-10 bg-white rounded-[2.5rem] border border-gray-100 shadow-sm">
               <h4 className="text-[10px] uppercase tracking-[0.4em] font-bold text-gray-400 mb-8">Milestones</h4>
               <div className="space-y-6">
                 {[
                   { icon: <ClipboardCheck size={18} />, title: 'Verification', date: 'Next 24h', active: true },
                   { icon: <Box size={18} />, title: 'Fabrication', date: 'Days 5-10', active: false },
                   { icon: <Calendar size={18} />, title: 'Dispatch', date: 'Est. Day 14', active: false }
                 ].map((s, i) => (
                   <div key={i} className={`flex items-center gap-6 ${s.active ? 'opacity-100' : 'opacity-20'}`}>
                     <div className="p-3 bg-gray-50 rounded-xl">{s.icon}</div>
                     <div><p className="text-[10px] font-bold uppercase">{s.title}</p><p className="text-[10px] text-gray-400">{s.date}</p></div>
                   </div>
                 ))}
               </div>
            </div>
            <div className="p-10 bg-luxury-black text-soft-white rounded-[2.5rem]">
               <h4 className="text-[10px] uppercase tracking-[0.4em] font-bold text-white/30 mb-8">Summary</h4>
               <div className="space-y-4 font-serif">
                 <div className="flex justify-between"><span>Batch Volume</span><span>{cart.reduce((a,b)=>a+b.quantity,0).toLocaleString()} Units</span></div>
                 <div className="flex justify-between text-2xl text-champagne-gold"><span>Total</span><span>₹{total.toLocaleString()}</span></div>
               </div>
               <Button onClick={onComplete} fullWidth className="mt-12 bg-soft-white text-luxury-black rounded-full">Return Home</Button>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-soft-white pt-40 px-8">
      <div className="max-w-5xl mx-auto">
        <button onClick={onBack} className="flex items-center gap-2 text-[10px] uppercase tracking-[0.4em] font-bold text-gray-400 mb-12"><ArrowLeft size={14}/> Return</button>
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-20">
          <div className="lg:col-span-2 space-y-12">
            <h1 className="text-6xl font-serif">Project Review.</h1>
            <div className="space-y-8">
              {cart.map(item => (
                <div key={item.id} className="flex gap-8 p-8 bg-white rounded-3xl border border-gray-100 items-center">
                  <div className="w-24 h-24 bg-gray-50 rounded-2xl overflow-hidden shrink-0"><img src={item.product.image} className="w-full h-full object-cover grayscale" /></div>
                  <div className="flex-1">
                    <h3 className="text-2xl font-serif">{item.product.name}</h3>
                    <p className="text-[10px] text-gray-400 uppercase tracking-widest">{item.options.texture} • {item.quantity} Units</p>
                  </div>
                  <div className="text-2xl font-serif">₹{item.totalPrice.toLocaleString()}</div>
                </div>
              ))}
            </div>
          </div>
          <div className="space-y-8">
            <div className="bg-luxury-black text-soft-white p-12 rounded-[3.5rem] shadow-2xl space-y-10">
              <h4 className="text-[10px] uppercase tracking-[0.4em] font-bold text-white/30">Logistics Summary</h4>
              <div className="space-y-6">
                <div className="flex justify-between text-[10px] uppercase tracking-widest font-bold"><span>Consolidated Value</span><span>₹{total.toLocaleString()}</span></div>
                <div className="flex justify-between text-[10px] uppercase tracking-widest font-bold"><span>Logistics Fee</span><span className="text-champagne-gold">Included</span></div>
                <div className="pt-6 border-t border-white/10 flex justify-between items-end">
                  <span className="text-[10px] uppercase tracking-[0.4em] font-bold">Final Brief</span>
                  <span className="text-4xl font-serif text-champagne-gold">₹{total.toLocaleString()}</span>
                </div>
              </div>
              <Button onClick={() => setStep('processing')} fullWidth size="lg" className="rounded-full bg-soft-white text-luxury-black font-bold h-20">Finalize & Pay</Button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

