                <p className="font-serif text-2xl">₹{cartTotal.toLocaleString()}</p>
              </div>
              <Button fullWidth size="lg" disabled={cart.length === 0} onClick={startCheckout} className="rounded-full shadow-xl">
                Initiate Project Protocol
