                      <div className="flex items-center gap-2 opacity-30 group-hover:opacity-100 transition-opacity">
                        <Leaf size={12} className="text-green-600" />
                        <span className="text-[10px] uppercase tracking-[0.2em] font-bold">Eco Score {product.ecoScore}</span>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </section>
        </main>
      ) : view === 'customizer' ? (
        <Customizer 
          product={selectedProduct || PRODUCTS[0]} 
          onBack={() => setView('showroom')} 
          onAddToCart={addToCart}
        />
      ) : view === 'checkout' ? (
        <Checkout 
          cart={cart} 
          total={cartTotal} 
          onBack={() => setView('showroom')} 
          onComplete={handleCompleteOrder}
        />
      ) : (
        <div className="min-h-screen pt-40 px-8 md:px-24 animate-in fade-in">
          <div className="max-w-6xl mx-auto">
            <h1 className="text-6xl font-serif mb-12">Project Ledger.</h1>
            {orders.length === 0 ? (
              <div className="text-center py-40 border border-dashed border-gray-200 rounded-[3rem]">
                <Briefcase size={48} className="mx-auto text-gray-200 mb-6" />
                <p className="text-gray-400 italic">No authenticated production protocols found.</p>
                <Button onClick={() => setView('showroom')} className="mt-8 rounded-full">Explore Archive</Button>
              </div>
            ) : (
              <div className="grid gap-12">
                {orders.map(order => (
                  <div key={order.id} className="bg-white rounded-[3rem] p-12 border border-gray-100 shadow-sm flex flex-col md:flex-row justify-between items-center gap-8">
                    <div className="flex-1">
                      <div className="flex items-center gap-4 mb-4">
                        <span className="text-[10px] uppercase tracking-[0.4em] font-bold text-champagne-gold">{order.status}</span>
                        <div className="w-1.5 h-1.5 rounded-full bg-champagne-gold animate-pulse" />
                      </div>
                      <h3 className="text-3xl font-serif mb-2 tracking-tight">Project #{order.id}</h3>
                      <p className="text-xs text-gray-400 uppercase tracking-widest">{order.date} • {order.items.length} Project Lines</p>
                    </div>
                    <div className="text-center md:text-right">
                      <p className="text-[10px] uppercase tracking-widest text-gray-400 mb-1">Authenticated Value</p>
                      <p className="text-3xl font-serif font-bold">₹{order.total.toLocaleString()}</p>
                      <Button variant="outline" size="sm" className="mt-4 rounded-full">Details</Button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      )}

      <button 
        onClick={() => setShowConcierge(true)}
        className="fixed bottom-12 right-12 z-50 group transform-gpu"
      >
        <div className="relative flex items-center gap-4 bg-luxury-black text-soft-white pl-8 pr-10 py-6 rounded-full shadow-[0_30px_60px_-15px_rgba(0,0,0,0.5)] border border-white/10 transition-all hover:scale-105 active:scale-95 group">
